impl DbMod {
    /// Detect if any download URL points to a GameBanana page (not a direct
    /// ZIP/LUA file). These require manual scraping or redirect handling in
    /// the download step (step 23).
    #[allow(dead_code)]
    pub fn requires_manual_download(&self) -> bool {
        self.download_urls.iter().any(|u| {
            let lower = u.to_lowercase();
            lower.contains("gamebanana.com")
        })
    }
}

