// Step 23a: HTTP download
// ═══════════════════════════════════════════════════════════════════════

/// Thread‑safe download progress. The worker thread writes updates via the
/// Mutex; the main loop reads them every frame to render the progress bar.
#[derive(Debug, Clone)]
pub struct DownloadProgress {
    pub bytes: u64,
    pub total: Option<u64>,
    pub done: bool,
    pub error: Option<String>,
    pub extracted: u32, // number of mods extracted (0 if download-only)
}

impl DownloadProgress {
    pub fn new(total: Option<u64>) -> Self {
        Self {
            bytes: 0,
            total,
            done: false,
            error: None,
            extracted: 0,
        }
    }

    pub fn pct(&self) -> u8 {
        if let Some(t) = self.total
            && t > 0
        {
            return ((self.bytes * 100) / t).min(100) as u8;
        }
        if self.done { 100 } else { 0 }
    }
}

/// Parse Content‑Disposition header to extract filename.
///
/// Supports:
///   `attachment; filename="file.zip"`
///   `attachment; filename*=UTF-8''file%20name.zip`
pub fn parse_content_disposition(cd: &str) -> Option<String> {
    // Try filename*= (RFC 5987)
    if let Some(start) = cd.to_lowercase().find("filename*=") {
        let rest = &cd[start + 10..]; // after "filename*="
        // Skip encoding prefix e.g. "UTF-8''"
        let after_encoding = if let Some(pos) = rest.find("''") {
            &rest[pos + 2..]
        } else {
            rest
        };
        // Decode percent‑encoding (simple: just %20 → space)
        let decoded: String = after_encoding.trim_matches('"').replace("%20", " ");
        if !decoded.is_empty() {
            return Some(decoded);
        }
    }

    // Try filename= (plain)
    if let Some(start) = cd.to_lowercase().find("filename=") {
        let rest = &cd[start + 9..]; // after "filename="
        let name = rest.trim().trim_matches('"');
        if !name.is_empty() {
            return Some(name.to_string());
        }
    }

    None
}

/// Extract the last filename segment from a URL path.
///
/// Removes query strings and fragments; returns the final path component.
/// e.g. "https://example.com/path/to/mod.zip?v=2" → "mod.zip"
pub fn filename_from_url(url: &str) -> String {
    // Simple extraction: find last '/' before '?' or '#', take the segment after
    let stripped = url.split('?').next().unwrap_or(url);
    let stripped = stripped.split('#').next().unwrap_or(stripped);
    let segments: Vec<&str> = stripped.rsplitn(2, '/').collect();
    let name = segments[0].trim();
    if name.is_empty() {
        "download.zip".to_string()
    } else {
        name.to_string()
    }
}

/// Resolve safe download filename: Content-Disposition → URL path → fallback.
pub fn resolve_download_filename(
    url: &str,
    content_disposition: Option<&str>,
    fallback_id: &str,
) -> String {
    if let Some(cd) = content_disposition
        && let Some(name) = parse_content_disposition(cd)
    {
        return sanitize_filename(&name);
    }
    let from_url = filename_from_url(url);
    if !from_url.is_empty() && from_url != "download.zip" {
        return sanitize_filename(&from_url);
    }
    // Fallback: use mod_id with .zip extension
    format!("{}.zip", sanitize_filename(fallback_id))
}

/// Strip or replace characters unsafe for filesystem names.
fn sanitize_filename(name: &str) -> String {
    name.chars()
        .map(|c| match c {
            '/' | '\\' | ':' | '*' | '?' | '"' | '<' | '>' | '|' => '_',
            c => c,
        })
        .collect()
}

/// Download a file from `url` into `dest_dir`, streaming to disk.
///
/// - `progress` is updated after each chunk (the main loop polls it).
/// - `cancel` is checked between chunks; if set, the download aborts and
///   the partial `.part` file is deleted.
/// - Returns the final `PathBuf` of the downloaded file on success.
pub fn download_mod_file(
    url: &str,
    dest_dir: &Path,
    filename_hint: &str,
    progress: &Arc<Mutex<DownloadProgress>>,
    cancel: &AtomicBool,
) -> Result<PathBuf, String> {
    let client = reqwest::blocking::Client::builder()
        .connect_timeout(Duration::from_secs(30))
        .timeout(None) // no total timeout — large mods take time
        .build()
        .map_err(|e| format!("Failed to create HTTP client: {e}"))?;

    let response = client
        .get(url)
        .header("User-Agent", "SM64CoopDX-Launcher/2.0")
        .send()
        .map_err(|e| {
            // Detect 404 / connection errors with a user‑friendly message
            if e.is_connect() {
                format!("Cannot connect to server for: {url}. Check your internet connection.")
            } else if e.is_timeout() {
                format!("Connection timed out downloading: {url}")
            } else {
                format!("Download failed for {url}: {e}")
            }
        })?;

    // Check HTTP status
    if !response.status().is_success() {
        return Err(format!(
            "Server returned HTTP {} for: {url}",
            response.status().as_u16()
        ));
    }

    let total_bytes = response.content_length();

    // Resolve filename
    let content_disp = response
        .headers()
        .get(reqwest::header::CONTENT_DISPOSITION)
        .and_then(|v| v.to_str().ok());
    let filename = resolve_download_filename(url, content_disp, filename_hint);

    let tmp_path = dest_dir.join(format!(".{}.part", filename));
    let final_path = dest_dir.join(&filename);

    // Ensure destination directory exists
    fs::create_dir_all(dest_dir)
        .map_err(|e| format!("Cannot create dest dir {}: {e}", dest_dir.display()))?;

    // Set initial progress
    {
        let mut p = progress.lock().map_err(|e| format!("Mutex: {e}"))?;
        p.bytes = 0;
        p.total = total_bytes;
        p.done = false;
        p.error = None;
    }

    // Stream body to disk
    let mut file = fs::File::create(&tmp_path)
        .map_err(|e| format!("Cannot create temp file {}: {e}", tmp_path.display()))?;

    let mut reader: Box<dyn Read> = Box::new(response);
    let mut buf = [0u8; 65536];
    let mut bytes_downloaded: u64 = 0;

    loop {
        // Check cancel before each chunk
        if cancel.load(Ordering::Relaxed) {
            drop(file);
            let _ = fs::remove_file(&tmp_path);
            {
                let mut p = progress.lock().map_err(|e| format!("Mutex: {e}"))?;
                p.done = true;
                p.error = Some("Download cancelled".to_string());
            }
            return Err("Download cancelled".to_string());
        }

        let n = reader
            .read(&mut buf)
            .map_err(|e| format!("Read error: {e}"))?;
        if n == 0 {
            break;
        }

        file.write_all(&buf[..n])
            .map_err(|e| format!("Write error to {}: {e}", tmp_path.display()))?;

        bytes_downloaded += n as u64;

        // Update progress every ~128KB to reduce mutex contention
        if bytes_downloaded % (128 * 1024) < n as u64 || n < 65536 {
            let mut p = progress.lock().map_err(|e| format!("Mutex: {e}"))?;
            p.bytes = bytes_downloaded;
            p.total = total_bytes;
        }
    }

    // Final progress update
    {
        let mut p = progress.lock().map_err(|e| format!("Mutex: {e}"))?;
        p.bytes = bytes_downloaded;
        p.total = total_bytes;
        p.done = true;
    }

    // Atomic rename: .part → final
    fs::rename(&tmp_path, &final_path).map_err(|e| {
        format!(
            "Failed to finalize download {} → {}: {e}",
            tmp_path.display(),
            final_path.display()
        )
    })?;

    log::info!(
        "Downloaded {} ({:.1} MB)",
        filename,
        bytes_downloaded as f64 / (1024.0 * 1024.0)
    );

    Ok(final_path)
}

// ═══════════════════════════════════════════════════════════════════════
// Step 23b: ZIP extraction
// ═══════════════════════════════════════════════════════════════════════

/// Extract a downloaded mod ZIP into `dest_root` (the mods directory).
///
/// Algorithm (per AGENTS.md "Extracción ZIP inteligente"):
/// 1. Scan all ZIP entries for files named `main.lua`.
/// 2. For each `main.lua` found, its parent directory is a **mod root**.
///    Extract all entries under that root to `dest_root/{mod_root_name}/`.
/// 3. If NO `main.lua` is found anywhere, fall back to extracting the
///    entire ZIP flat into `dest_root/`.
/// 4. Zip‑slip guard: entries with `../` or absolute paths are rejected
///    individually without aborting the rest of the extraction.
///
/// Returns a list of final mod directories (one per mod root).
pub fn extract_mod_zip(zip_path: &Path, dest_root: &Path) -> Result<Vec<PathBuf>, String> {
    let file = fs::File::open(zip_path)
        .map_err(|e| format!("Cannot open ZIP {}: {e}", zip_path.display()))?;

    let mut archive = zip::ZipArchive::new(file)
        .map_err(|e| format!("Invalid ZIP {}: {e}", zip_path.display()))?;

    // ── Pass 1: find all main.lua entries ──
    let mut main_lua_paths: Vec<String> = Vec::new();
    for i in 0..archive.len() {
        let entry = archive
            .by_index(i)
            .map_err(|e| format!("ZIP entry {i}: {e}"))?;
        let name = entry.name().to_string();
        if name.ends_with("main.lua") {
            // Normalize: remove trailing "main.lua", keep the parent directory
            let dir = if let Some(pos) = name.rfind('/') {
                &name[..pos + 1] // includes trailing /
            } else {
                ""
            };
            main_lua_paths.push(dir.to_string());
        }
    }

    // Deduplicate mod roots (multiple main.lua in same dir is same root)
    let mut mod_roots: Vec<String> = main_lua_paths;
    mod_roots.sort();
    mod_roots.dedup();

    // ── Pass 2: extract ──
    fs::create_dir_all(dest_root)
        .map_err(|e| format!("Cannot create dest dir {}: {e}", dest_root.display()))?;

    let mut extracted_dirs: Vec<PathBuf> = Vec::new();

    // Pre‑compute safe root paths for zip‑slip validation
    let dest_canon = dest_root
        .canonicalize()
        .unwrap_or_else(|_| dest_root.to_path_buf());

    if !mod_roots.is_empty() {
        // ── Mod‑root extraction (one subfolder per mod root) ──
        for root in &mod_roots {
            // Determine folder name: last meaningful segment of the root path
            let folder_name = root
                .trim_end_matches('/')
                .rsplit('/')
                .next()
                .unwrap_or("unknown");
            if folder_name.is_empty() {
                // main.lua at ZIP root → use ZIP filename as folder
                if let Some(stem) = zip_path.file_stem().and_then(|s| s.to_str()) {
                    let mod_dir = dest_root.join(stem);
                    fs::create_dir_all(&mod_dir)
                        .map_err(|e| format!("Cannot create mod dir {}: {e}", mod_dir.display()))?;
                    extracted_dirs.push(mod_dir);
                }
                continue;
            }
            let mod_dir = dest_root.join(folder_name);
            let created = !mod_dir.exists();
            if created {
                fs::create_dir_all(&mod_dir)
                    .map_err(|e| format!("Cannot create mod dir {}: {e}", mod_dir.display()))?;
            }
            if !extracted_dirs.iter().any(|d| d == &mod_dir) {
                extracted_dirs.push(mod_dir.clone());
            }
        }

        // Re‑open archive for extraction pass (entries consumed by by_index)
        let file2 = fs::File::open(zip_path).map_err(|e| format!("Cannot reopen ZIP: {e}"))?;
        let mut archive2 =
            zip::ZipArchive::new(file2).map_err(|e| format!("Invalid ZIP on re‑open: {e}"))?;

        for i in 0..archive2.len() {
            let mut entry = archive2
                .by_index(i)
                .map_err(|e| format!("ZIP entry {i}: {e}"))?;
            let entry_name = entry.name().to_string();

            if entry.is_dir() {
                continue;
            }

            // Determine which mod root this entry belongs to
            let matched_root = mod_roots
                .iter()
                .find(|r| entry_name.starts_with(r.as_str()));

            let (target_dir, rel_path) = if let Some(root) = matched_root {
                let folder_name = root
                    .trim_end_matches('/')
                    .rsplit('/')
                    .next()
                    .unwrap_or("unknown");
                let folder_name = if folder_name.is_empty() {
                    zip_path
                        .file_stem()
                        .and_then(|s| s.to_str())
                        .unwrap_or("unknown")
                } else {
                    folder_name
                };
                let stripped = entry_name
                    .strip_prefix(root.as_str())
                    .unwrap_or(&entry_name);
                (dest_root.join(folder_name), stripped.to_string())
            } else {
                // Entry outside any mod root — skip (it's not part of any mod)
                continue;
            };

            // Zip‑slip guard
            let resolved = target_dir.join(&rel_path);
            if !resolved.starts_with(&dest_canon) {
                log::warn!(
                    "Zip‑slip rejected: '{}' resolves outside dest_root",
                    entry_name
                );
                continue;
            }

            // Create parent directories
            if let Some(parent) = resolved.parent() {
                fs::create_dir_all(parent)
                    .map_err(|e| format!("Cannot create dir {}: {e}", parent.display()))?;
            }

            let mut out_file = fs::File::create(&resolved)
                .map_err(|e| format!("Cannot create {}: {e}", resolved.display()))?;

            // read_all avoids decompression errors from is_file() + read() pattern
            let mut buf = Vec::new();
            entry
                .read_to_end(&mut buf)
                .map_err(|e| format!("Decompress error for '{}': {e}", entry_name))?;
            out_file
                .write_all(&buf)
                .map_err(|e| format!("Write error for {}: {e}", resolved.display()))?;
        }
    } else {
        // ── Fallback: no main.lua found → extract flat ──
        let flat_dir = dest_root.to_path_buf();
        if !flat_dir.exists() {
            fs::create_dir_all(&flat_dir).map_err(|e| format!("Cannot create flat dir: {e}"))?;
        }
        extracted_dirs.push(flat_dir.clone());

        let file2 = fs::File::open(zip_path).map_err(|e| format!("Cannot reopen ZIP: {e}"))?;
        let mut archive2 =
            zip::ZipArchive::new(file2).map_err(|e| format!("Invalid ZIP on re‑open: {e}"))?;

        for i in 0..archive2.len() {
            let mut entry = archive2
                .by_index(i)
                .map_err(|e| format!("ZIP entry {i}: {e}"))?;
            let entry_name = entry.name().to_string();

            if entry.is_dir() {
                continue;
            }

            // Strip any leading directory component (extract flat)
            let rel_path = if let Some(pos) = entry_name.rfind('/') {
                &entry_name[pos + 1..]
            } else {
                &entry_name
            };

            let resolved = flat_dir.join(rel_path);
            if !resolved.starts_with(&dest_canon) {
                log::warn!(
                    "Zip‑slip rejected (flat): '{}' resolves outside dest_root",
                    entry_name
                );
                continue;
            }

            if let Some(parent) = resolved.parent() {
                fs::create_dir_all(parent)
                    .map_err(|e| format!("Cannot create dir {}: {e}", parent.display()))?;
            }

            let mut out_file = fs::File::create(&resolved)
                .map_err(|e| format!("Cannot create {}: {e}", resolved.display()))?;

            let mut buf = Vec::new();
            entry
                .read_to_end(&mut buf)
                .map_err(|e| format!("Decompress error for '{}': {e}", entry_name))?;
            out_file
                .write_all(&buf)
                .map_err(|e| format!("Write error for {}: {e}", resolved.display()))?;
        }
    }

    log::info!(
        "Extracted {} mod(s) from {}",
        extracted_dirs.len(),
        zip_path.display()
    );
    Ok(extracted_dirs)
}

// ═══════════════════════════════════════════════════════════════════════
// Step 24: installed mod detection
// ═══════════════════════════════════════════════════════════════════════

/// Normalize a string for fuzzy matching: lowercase + alphanumeric only.
/// NEVER use for display; this strips all whitespace and punctuation.
pub fn normalize(s: &str) -> String {
    s.to_lowercase()
        .chars()
        .filter(|c| c.is_alphanumeric())
        .collect()
}

/// Persistent mapping: folder name → DB mod_id.
pub type InstalledMap = HashMap<String, String>;

/// Load the installed‑mod mapping from `launcher_downloads.json`.
/// Returns empty HashMap if the file doesn't exist or is corrupt.
pub fn load_installed_map(path: &Path) -> InstalledMap {
    match fs::read_to_string(path) {
        Ok(json) => serde_json::from_str(&json).unwrap_or_default(),
        Err(_) => HashMap::new(),
    }
}

/// Save the installed‑mod mapping to disk atomically.
pub fn save_installed_map(path: &Path, map: &InstalledMap) -> Result<(), String> {
    let tmp = path.with_extension(".tmp");
    let json = serde_json::to_string_pretty(map).map_err(|e| format!("JSON serialize: {e}"))?;
    fs::write(&tmp, &json).map_err(|e| format!("Cannot write to {}: {e}", tmp.display()))?;
    fs::rename(&tmp, path)
        .map_err(|e| format!("Cannot rename {} → {}: {e}", tmp.display(), path.display()))
}

/// Parse the `-- id:` or `-- name:` header from a `main.lua` file.
/// Returns `Some(id)` or `Some(name)` if a header is found, `None` otherwise.
fn parse_main_lua_header(path: &Path) -> Option<String> {
    let content = fs::read_to_string(path).ok()?;
    for line in content.lines().take(40) {
        let trimmed = line.trim();
        if let Some(stripped) = trimmed.strip_prefix("-- id:") {
            return Some(stripped.trim().to_string());
        }
        if let Some(stripped) = trimmed.strip_prefix("-- name:") {
            return Some(stripped.trim().to_string());
        }
    }
    None
}

/// Multi‑strategy installed‑mod detection (per AGENTS.md §9.4):
///
/// 1. **Exact normalized match** — compare `normalize(installed_folder_name)`
///    against `normalize(title)` + `normalize(mod_id)` for every entry in the
///    search index.
/// 2. **Persistent mapping** — `launcher_downloads.json` stores folder → mod_id
///    pairs from previous matches and manual assignments.
/// 3. **Auto‑map from main.lua headers** — read `-- id:` / `-- name:` from
///    each mod's `main.lua`; only accept if the match is unambiguous (≥6 chars
///    and exactly 1 result in the DB).
///
/// Returns the set of DB mod_ids that are known to be installed.
pub fn detect_installed_mods(
    installed_dirs: &[PathBuf],
    index: &SearchIndex,
    installed_map: &InstalledMap,
) -> HashSet<String> {
    let mut detected: HashSet<String> = HashSet::new();

    for dir in installed_dirs {
        let Some(folder_name) = dir.file_name().and_then(|n| n.to_str()) else {
            continue;
        };

        // ── Strategy 1: exact normalized match ──
        let norm_folder = normalize(folder_name);
        let mut found = false;
        for entry in &index.entries {
            // Match against normalized display title and mod_id
            let norm_title = normalize(&entry.title_display);
            let norm_id = normalize(&entry.mod_id);
            if norm_folder == norm_title || norm_folder == norm_id {
                detected.insert(entry.mod_id.clone());
                found = true;
                break;
            }
        }
        if found {
            continue;
        }

        // ── Strategy 2: persistent mapping ──
        if let Some(mapped_id) = installed_map.get(folder_name) {
            // Verify the mapped ID still exists in the index
            if index.entries.iter().any(|e| &e.mod_id == mapped_id) {
                detected.insert(mapped_id.clone());
                continue;
            }
        }

        // ── Strategy 3: auto‑map from main.lua headers ──
        let lua_path = dir.join("main.lua");
        if let Some(header_id) = parse_main_lua_header(&lua_path) {
            let norm_hdr = normalize(&header_id);
            // Only accept if ≥6 chars and exactly 1 unambiguous result
            if norm_hdr.len() >= 6 {
                let matches: Vec<usize> = index
                    .entries
                    .iter()
                    .enumerate()
                    .filter(|(_, e)| {
                        normalize(&e.mod_id) == norm_hdr || normalize(&e.title_display) == norm_hdr
                    })
                    .map(|(i, _)| i)
                    .collect();

                if matches.len() == 1 {
                    detected.insert(index.entries[matches[0]].mod_id.clone());
                }
            }
        }
    }

    detected
}

