    #[test]
    fn normalize_lowercase_alnum_only() {
        assert_eq!(normalize("Super Mod 2024!"), "supermod2024");
        assert_eq!(normalize("Co-Op: DX"), "coopdx");
        assert_eq!(normalize("   Spaces   "), "spaces");
        assert_eq!(normalize("UPPER.lower"), "upperlower");
    }

    #[test]
    fn detect_exact_normalized_match() {
        let json = r#"{"mods": {"mod.123": {"id": "mod.123", "title": "Super Coop Mod 2024!"}, "unrelated": {"id": "unrelated", "title": "Other Mod"}}}"#;
        let db: DbFile = serde_json::from_str(json).unwrap();
        let idx = build_search_index(&db);

        // Folder named "SuperCoopMod2024" (normalized match with "Super Coop Mod 2024!")
        let tmp = std::env::temp_dir().join("sm64launcher_detect_test_1");
        let _ = std::fs::remove_dir_all(&tmp);
        std::fs::create_dir_all(&tmp.join("SuperCoopMod2024")).unwrap();
        std::fs::create_dir_all(&tmp.join("OtherRandomFolder")).unwrap();

        let dirs: Vec<PathBuf> = std::fs::read_dir(&tmp)
            .unwrap()
            .filter_map(|e| e.ok().map(|e| e.path()))
            .collect();

        let map: InstalledMap = HashMap::new();
        let detected = detect_installed_mods(&dirs, &idx, &map);

        assert!(detected.contains("mod.123"));
        assert!(!detected.contains("unrelated"));

        let _ = std::fs::remove_dir_all(&tmp);
    }

