        println!("── Real database metrics ──");
        println!("  Mods:         {}", db.mods.len());
        println!("  Load time:    {load_ms:.1} ms");
        println!("  Index time:   {idx_ms:.1} ms");
        println!("  Total:        {:.1} ms", load_ms + idx_ms);
        println!("  Unique tags:  {}", idx.tag_frequency.len());
        println!("  Unique authors: {}", idx.authors_sorted.len());
