    // ── Step 21 tests ──

    #[test]
    fn top_9_tags_by_frequency() {
        let mut tag_frequency: HashMap<String, usize> = HashMap::new();
        // 10 tags: a0-a9 with counts 0..9, then c0 with count 100
        for i in 0..10u8 {
            tag_frequency.insert(format!("a{i}"), i as usize);
        }
        tag_frequency.insert("c0".into(), 100);
        // Also add tie: two tags with same count
        tag_frequency.insert("b0".into(), 50);
        tag_frequency.insert("b1".into(), 50);

        let index = SearchIndex {
            entries: Vec::new(),
            tag_frequency,
            authors_sorted: Vec::new(),
        };

        let top = top_tags(&index, 9);
        // Should be the 9 most frequent, descending
        assert_eq!(top.len(), 9);
        assert_eq!(top[0], ("c0".to_string(), 100));
        // b0 and b1 tied at 50, sorted alphabetically within tie
        assert_eq!(top[1], ("b0".to_string(), 50));
        assert_eq!(top[2], ("b1".to_string(), 50));
        // a9 (9) ... a4 (4) = 6 items, total 9
        assert_eq!(top[3], ("a9".to_string(), 9));
        // a8, a7, a6, a5, a4 should be the remaining
        assert_eq!(top[8], ("a4".to_string(), 4));
    }

