    /// Mock server test: spawn a tiny HTTP server on localhost, serve a
    /// known payload, download it via download_mod_file, verify content.
    #[test]
    fn mock_download_small_file() {
        use std::io::Write;
        use std::net::TcpListener;
        use std::thread;

        let payload = b"Hello, this is a test mod file!\nIt has 51 bytes.";
        let payload_len = payload.len() as u64;

        // Bind to random port
        let listener = TcpListener::bind("127.0.0.1:0").unwrap();
        let addr = listener.local_addr().unwrap();
        let url = format!("http://{addr}/test.zip");

        let server_thread = thread::spawn(move || {
            for stream in listener.incoming() {
                if let Ok(mut s) = stream {
                    let _ = s.write_all(
                        format!(
                            "HTTP/1.1 200 OK\r\n\
                             Content-Type: application/zip\r\n\
                             Content-Length: {payload_len}\r\n\
                             Content-Disposition: attachment; filename=\"test_mod.zip\"\r\n\
                             Connection: close\r\n\
                             \r\n"
                        )
                        .as_bytes(),
                    );
                    let _ = s.write_all(payload);
                    let _ = s.flush();
                    // Only serve one request, then stop
                    break;
                }
            }
        });

        let progress = Arc::new(Mutex::new(DownloadProgress::new(None)));
        let cancel = Arc::new(AtomicBool::new(false));
        let tmp_dir = std::env::temp_dir().join("sm64launcher_dl_test");

        let _ = std::fs::remove_dir_all(&tmp_dir);
        std::fs::create_dir_all(&tmp_dir).unwrap();

        let result = download_mod_file(&url, &tmp_dir, "fallback", &progress, &cancel);

        let _ = server_thread.join();
        let _ = std::fs::remove_dir_all(&tmp_dir);

        match result {
            Ok(path) => {
                assert!(path.file_name().unwrap() == "test_mod.zip");

                let progr = progress.lock().unwrap();
                assert!(progr.done);
                assert_eq!(progr.bytes, payload_len);
                assert!(progr.error.is_none());
            }
            Err(e) => panic!("Download should succeed but got error: {e}"),
        }
    }

    /// build_search_index() excludes mods with requires_manual_download=true.
    /// These are GameBanana page URLs, not direct ZIP archives — they can't
    /// be downloaded automatically, so they're excluded from the searchable
    /// mod list entirely (step 23c decision).
    #[test]
    fn build_search_index_excludes_gamebanana() {
        let json = r#"{"mods":{"normal":{"id":"normal","title":"Normal","download_urls":["https://mods.sm64coopdx.com/mod.zip"]},"gb1":{"id":"gb1","title":"GB1","download_urls":["https://gamebanana.com/mods/1"]},"gb2":{"id":"gb2","title":"GB2","download_urls":["https://www.gamebanana.com/dl/2"]},"normal2":{"id":"normal2","title":"N2","download_urls":["https://example.com/mod.zip"]}}}"#;
        let db: DbFile = serde_json::from_str(json).unwrap();

        let idx = build_search_index(&db);
        // Only the 2 non‑GameBanana mods should be in the index
        assert_eq!(idx.entries.len(), 2);
        let ids: Vec<&str> = idx.entries.iter().map(|e| e.mod_id.as_str()).collect();
        assert!(ids.contains(&"normal"));
        assert!(ids.contains(&"normal2"));
        assert!(!ids.contains(&"gb1"));
        assert!(!ids.contains(&"gb2"));

        // Tag frequency and author counts should NOT include excluded mods
        // (in this fixture, no tags/authors, so just verifying it doesn't panic)
        assert!(idx.tag_frequency.is_empty());
        assert!(idx.authors_sorted.is_empty());
    }

    /// Real download test — validates Content-Length match, filename
    /// resolution (via Content-Disposition), and bytes reported match
    /// file size. Requires internet access.
    #[test]
    #[ignore]
    fn real_download_small_mod() {
        let url = "https://mods.sm64coopdx.com/mods/15.681/download";
        let progress = Arc::new(Mutex::new(DownloadProgress::new(None)));
        let cancel = Arc::new(AtomicBool::new(false));
        let dest_dir = std::env::temp_dir().join("sm64launcher_real_dl_test");

        let _ = std::fs::remove_dir_all(&dest_dir);
        std::fs::create_dir_all(&dest_dir).unwrap();

        let result = download_mod_file(url, &dest_dir, "15.681", &progress, &cancel);

        let progr = progress.lock().unwrap();
        assert!(progr.done);
        assert!(progr.error.is_none(), "Download error: {:?}", progr.error);

        match result {
            Ok(path) => {
                let fname = path.file_name().unwrap().to_str().unwrap();
                assert_eq!(fname, "15.zip");

                let meta = std::fs::metadata(&path).unwrap();
                let actual_bytes = meta.len();
                assert_eq!(actual_bytes, progr.bytes);
                if let Some(total) = progr.total {
                    assert_eq!(actual_bytes, total);
                }
                println!("── Real download verified ──");
                println!("  File:  {fname}  ({actual_bytes} bytes)");
                let _ = std::fs::remove_file(&path);
            }
            Err(e) => panic!("Download failed: {e}"),
        }
        let _ = std::fs::remove_dir_all(&dest_dir);
    }

    /// Cancel test: verify no .part files remain after abort.
    #[test]
    #[ignore]
    fn real_download_cancel_cleanup() {
        let url = "https://mods.sm64coopdx.com/mods/15.681/download";
        let progress = Arc::new(Mutex::new(DownloadProgress::new(None)));
        let cancel = Arc::new(AtomicBool::new(false));
        let dest_dir = std::env::temp_dir().join("sm64launcher_cancel_test");

        let _ = std::fs::remove_dir_all(&dest_dir);
        std::fs::create_dir_all(&dest_dir).unwrap();

        cancel.store(true, Ordering::Relaxed);
        let result = download_mod_file(url, &dest_dir, "15.681", &progress, &cancel);

        let progr = progress.lock().unwrap();
        assert!(progr.error.is_some());
        assert!(result.is_err());

        let entries: Vec<_> = std::fs::read_dir(&dest_dir)
            .unwrap()
            .filter_map(|e| e.ok())
            .collect();
        assert!(entries.is_empty(), "Expected empty dir after cancel");
        println!("── Cancel cleanup verified ──");
        let _ = std::fs::remove_dir_all(&dest_dir);
    }

    // ── Step 23b tests ──

    /// Build an in‑memory ZIP and write it to `path`.
    fn build_test_zip(path: &Path, entries: &[(&str, &[u8])]) {
        let file = std::fs::File::create(path).unwrap();
        let mut writer = zip::ZipWriter::new(file);
        let opts = zip::write::SimpleFileOptions::default()
            .compression_method(zip::CompressionMethod::Deflated);
        for (name, data) in entries {
            writer.start_file(*name, opts).unwrap();
            writer.write_all(data).unwrap();
        }
        writer.finish().unwrap();
    }

    #[test]
    fn extract_finds_single_mod_root() {
        let tmp = std::env::temp_dir().join("sm64launcher_zip_test_1");
        let _ = std::fs::remove_dir_all(&tmp);
        std::fs::create_dir_all(&tmp).unwrap();

        let zip_path = tmp.join("mod.zip");
        build_test_zip(
            &zip_path,
            &[
                ("super_mod/main.lua", b"-- Super Mod\n"),
                ("super_mod/script.lua", b"print('ok')\n"),
                ("super_mod/assets/tex.png", b"PNGfake"),
                ("readme.txt", b"top-level file"),
            ],
        );

        let dest = tmp.join("mods");
        let result = extract_mod_zip(&zip_path, &dest).unwrap();
        assert_eq!(result.len(), 1);
        assert!(result[0].ends_with("super_mod"));

        // Verify files exist
        assert!(dest.join("super_mod/main.lua").exists());
        assert!(dest.join("super_mod/script.lua").exists());
        assert!(dest.join("super_mod/assets/tex.png").exists());
        // readme.txt at zip root should NOT be extracted (outside mod root)
        assert!(!dest.join("super_mod/readme.txt").exists());

        let _ = std::fs::remove_dir_all(&tmp);
    }

