    #[test]
    fn extract_rejects_zip_slip() {
        let tmp = std::env::temp_dir().join("sm64launcher_zip_test_4");
        let _ = std::fs::remove_dir_all(&tmp);
        std::fs::create_dir_all(&tmp).unwrap();

        let zip_path = tmp.join("slip.zip");
        build_test_zip(
            &zip_path,
            &[
                ("safe_mod/main.lua", b"-- Safe\n"),
                ("safe_mod/ok.txt", b"ok\n"),
                // Zip‑slip attempt: path traversal
                ("safe_mod/../../../etc/evil.txt", b"bad\n"),
                // Absolute path attempt
                ("safe_mod//etc/passwd", b"bad\n"),
            ],
        );

        let dest = tmp.join("mods_out");
        let result = extract_mod_zip(&zip_path, &dest).unwrap();
        assert_eq!(result.len(), 1);

        // Safe files extracted
        assert!(dest.join("safe_mod/main.lua").exists());
        assert!(dest.join("safe_mod/ok.txt").exists());

        // Zip‑slip entries must NOT exist anywhere under dest
        assert!(!dest.join("etc/evil.txt").exists());
        assert!(!dest.join("../../../etc/evil.txt").exists());

        let _ = std::fs::remove_dir_all(&tmp);
    }

    /// End-to-end pipeline test: download a real mod -> extract -> detect.
    /// Verifies that the installed detection recognizes the mod without
    /// manual intervention. Requires internet access.
    #[test]
    #[ignore]
    fn e2e_real_mod_download_extract_detect() {
        let url = "https://mods.sm64coopdx.com/mods/15.681/download";
        let progress = Arc::new(Mutex::new(DownloadProgress::new(None)));
        let cancel = Arc::new(AtomicBool::new(false));
        let e2e_root = std::env::temp_dir().join("sm64launcher_e2e_test");

        let _ = std::fs::remove_dir_all(&e2e_root);
        std::fs::create_dir_all(&e2e_root).unwrap();

        let dl_dir = e2e_root.join("_downloads");
        std::fs::create_dir_all(&dl_dir).unwrap();
        let mods_dir = e2e_root.join("mods");

        // Download
        let zip_path = download_mod_file(url, &dl_dir, "15.681", &progress, &cancel).unwrap();
        let progr = progress.lock().unwrap();
        assert!(progr.done);
        assert!(progr.error.is_none());
        assert_eq!(progr.bytes, 649_293);
        println!("  Download: OK");

        // Extract
        let extracted = extract_mod_zip(&zip_path, &mods_dir).unwrap();
        let _ = std::fs::remove_file(&zip_path);
        assert_eq!(extracted.len(), 1);
        let mod_dir = &extracted[0];
        assert!(mod_dir.join("main.lua").exists());
        println!("  Extract: OK -> {}", mod_dir.display());

        // Detect
        let db_path = Path::new(concat!(
            env!("CARGO_MANIFEST_DIR"),
            "/../assets/database_sm64coopdx.json"
        ));
        let db = load_database(db_path).unwrap();
        let idx = build_search_index(&db);

        let installed_dirs: Vec<PathBuf> = std::fs::read_dir(&mods_dir)
            .unwrap()
            .filter_map(|e| e.ok().map(|e| e.path()))
            .collect();

        let detected = detect_installed_mods(&installed_dirs, &idx, &HashMap::new());

        assert!(
            !detected.is_empty(),
            "Expected at least one detected mod, got none"
        );
        println!(
            "  Detect: OK — {} installed mod(s) detected:",
            detected.len()
        );
        for id in &detected {
            let title = idx
                .entries
                .iter()
                .find(|e| &e.mod_id == id)
                .map(|e| e.title_display.as_str())
                .unwrap_or("?");
            println!("    {} (title: {title})", id);
        }

        let _ = std::fs::remove_dir_all(&e2e_root);
    }
